// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Revoke all of the user's sessions.
	// (POST /account/logout-all)
	LogoutAll(ctx context.Context, request LogoutAllRequestObject) (LogoutAllResponseObject, error)
	// Cross-org billing summary (platform admins only).
	// (GET /admin/billing)
	GetAdminBilling(ctx context.Context, request GetAdminBillingRequestObject) (GetAdminBillingResponseObject, error)
	// Platform-wide totals (platform admins only).
	// (GET /admin/metrics)
	GetAdminMetrics(ctx context.Context, request GetAdminMetricsRequestObject) (GetAdminMetricsResponseObject, error)
	// Every organization with its plan (platform admins only).
	// (GET /admin/orgs)
	ListAdminOrgs(ctx context.Context, request ListAdminOrgsRequestObject) (ListAdminOrgsResponseObject, error)
	// Set an organization's plan (platform admins only).
	// (PUT /admin/orgs/{orgId}/plan)
	SetAdminOrgPlan(ctx context.Context, request SetAdminOrgPlanRequestObject) (SetAdminOrgPlanResponseObject, error)
	// Refund an org's payment (platform admins only).
	// (POST /admin/orgs/{orgId}/refund)
	RefundAdminOrgPayment(ctx context.Context, request RefundAdminOrgPaymentRequestObject) (RefundAdminOrgPaymentResponseObject, error)
	// Cancel an organization's subscription (platform admins only).
	// (POST /admin/orgs/{orgId}/subscription/cancel)
	CancelAdminOrgSubscription(ctx context.Context, request CancelAdminOrgSubscriptionRequestObject) (CancelAdminOrgSubscriptionResponseObject, error)
	// Preview an invitation by its token (org name, role, inviter). Usable pre-login via the token capability, so the accept page can render before sign-in.
	// (GET /invitations/{token})
	GetInvitationPreview(ctx context.Context, request GetInvitationPreviewRequestObject) (GetInvitationPreviewResponseObject, error)
	// Accept an invitation. Requires a signed-in session whose verified email matches the invited email; creates the membership and occupies the seat.
	// (POST /invitations/{token}/accept)
	AcceptInvitation(ctx context.Context, request AcceptInvitationRequestObject) (AcceptInvitationResponseObject, error)
	// The signed-in user and the orgs they belong to.
	// (GET /me)
	GetMe(ctx context.Context, request GetMeRequestObject) (GetMeResponseObject, error)
	// Update the signed-in user's profile (name, locale, timezone).
	// (PATCH /me)
	UpdateMe(ctx context.Context, request UpdateMeRequestObject) (UpdateMeResponseObject, error)
	// The social identities linked to the signed-in user.
	// (GET /me/identities)
	ListMyIdentities(ctx context.Context, request ListMyIdentitiesRequestObject) (ListMyIdentitiesResponseObject, error)
	// Unlink a social identity from the signed-in user.
	// (DELETE /me/identities/{provider})
	UnlinkMyIdentity(ctx context.Context, request UnlinkMyIdentityRequestObject) (UnlinkMyIdentityResponseObject, error)
	// The orgs the signed-in user belongs to.
	// (GET /orgs)
	ListOrgs(ctx context.Context, request ListOrgsRequestObject) (ListOrgsResponseObject, error)
	// Create a new org with the caller as owner.
	// (POST /orgs)
	CreateOrg(ctx context.Context, request CreateOrgRequestObject) (CreateOrgResponseObject, error)
	// One org the caller is a member of.
	// (GET /orgs/{orgId})
	GetOrg(ctx context.Context, request GetOrgRequestObject) (GetOrgResponseObject, error)
	// The org's API keys (metadata only; the secret is never returned).
	// (GET /orgs/{orgId}/api-keys)
	ListAPIKeys(ctx context.Context, request ListAPIKeysRequestObject) (ListAPIKeysResponseObject, error)
	// Create an API key. The full secret (pulse_sk_...) is returned exactly once in this response and never again. Role is member or admin only.
	// (POST /orgs/{orgId}/api-keys)
	CreateAPIKey(ctx context.Context, request CreateAPIKeyRequestObject) (CreateAPIKeyResponseObject, error)
	// Revoke an API key. The key fails auth immediately after.
	// (DELETE /orgs/{orgId}/api-keys/{id})
	RevokeAPIKey(ctx context.Context, request RevokeAPIKeyRequestObject) (RevokeAPIKeyResponseObject, error)
	// Start a hosted checkout to buy a paid plan (owner/admin).
	// (POST /orgs/{orgId}/billing/checkout)
	CreateBillingCheckout(ctx context.Context, request CreateBillingCheckoutRequestObject) (CreateBillingCheckoutResponseObject, error)
	// The org's payments (invoices), newest first (owner/admin).
	// (GET /orgs/{orgId}/billing/payments)
	ListBillingPayments(ctx context.Context, request ListBillingPaymentsRequestObject) (ListBillingPaymentsResponseObject, error)
	// Open the provider customer portal (owner/admin).
	// (POST /orgs/{orgId}/billing/portal)
	CreateBillingPortal(ctx context.Context, request CreateBillingPortalRequestObject) (CreateBillingPortalResponseObject, error)
	// The channel-type catalog: every notification channel type, its config-field schema, and whether the org's plan includes it. Drives the channel picker and config forms with no hardcoding (RFC-007a, PRD-006 section 3).
	// (GET /orgs/{orgId}/channel-types)
	GetChannelTypes(ctx context.Context, request GetChannelTypesRequestObject) (GetChannelTypesResponseObject, error)

	// (GET /orgs/{orgId}/channels)
	ListChannels(ctx context.Context, request ListChannelsRequestObject) (ListChannelsResponseObject, error)

	// (POST /orgs/{orgId}/channels)
	CreateChannel(ctx context.Context, request CreateChannelRequestObject) (CreateChannelResponseObject, error)

	// (DELETE /orgs/{orgId}/channels/{id})
	DeleteChannel(ctx context.Context, request DeleteChannelRequestObject) (DeleteChannelResponseObject, error)

	// (PUT /orgs/{orgId}/channels/{id})
	UpdateChannel(ctx context.Context, request UpdateChannelRequestObject) (UpdateChannelResponseObject, error)

	// (POST /orgs/{orgId}/channels/{id}/test)
	TestChannel(ctx context.Context, request TestChannelRequestObject) (TestChannelResponseObject, error)
	// The active org's plan, usage, and caps (owner/admin).
	// (GET /orgs/{orgId}/entitlements)
	GetEntitlements(ctx context.Context, request GetEntitlementsRequestObject) (GetEntitlementsResponseObject, error)
	// The org's incidents across all monitors, newest first (PRD-002 4). status filters to currently open incidents; the default returns all.
	// (GET /orgs/{orgId}/incidents)
	ListIncidents(ctx context.Context, request ListIncidentsRequestObject) (ListIncidentsResponseObject, error)
	// One incident with its annotation timeline (PRD-002 4). Any member may view.
	// (GET /orgs/{orgId}/incidents/{id})
	GetIncident(ctx context.Context, request GetIncidentRequestObject) (GetIncidentResponseObject, error)
	// Add a note to the incident timeline (PRD-002 4). Member+ may annotate.
	// (POST /orgs/{orgId}/incidents/{id}/annotations)
	AddIncidentAnnotation(ctx context.Context, request AddIncidentAnnotationRequestObject) (AddIncidentAnnotationResponseObject, error)
	// Manually close an open incident as an operator override (PRD-002 4). Owner or admin only. Sets a distinct manual close_reason and emits no recovery notification. An already-closed incident is a 409.
	// (POST /orgs/{orgId}/incidents/{id}/close)
	CloseIncident(ctx context.Context, request CloseIncidentRequestObject) (CloseIncidentResponseObject, error)
	// The pending invitations for the org.
	// (GET /orgs/{orgId}/invitations)
	ListInvitations(ctx context.Context, request ListInvitationsRequestObject) (ListInvitationsResponseObject, error)
	// Invite a teammate by email with a target role.
	// (POST /orgs/{orgId}/invitations)
	CreateInvitation(ctx context.Context, request CreateInvitationRequestObject) (CreateInvitationResponseObject, error)
	// Revoke a pending invitation, freeing its reserved seat.
	// (DELETE /orgs/{orgId}/invitations/{id})
	RevokeInvitation(ctx context.Context, request RevokeInvitationRequestObject) (RevokeInvitationResponseObject, error)
	// Resend a pending invitation with a fresh token and 7-day expiry.
	// (POST /orgs/{orgId}/invitations/{id}/resend)
	ResendInvitation(ctx context.Context, request ResendInvitationRequestObject) (ResendInvitationResponseObject, error)
	// The members of the org with their role and user info.
	// (GET /orgs/{orgId}/members)
	ListMembers(ctx context.Context, request ListMembersRequestObject) (ListMembersResponseObject, error)
	// Leave the org. The last owner must transfer ownership first.
	// (DELETE /orgs/{orgId}/members/me)
	LeaveOrg(ctx context.Context, request LeaveOrgRequestObject) (LeaveOrgResponseObject, error)
	// Remove a member from the org.
	// (DELETE /orgs/{orgId}/members/{userId})
	RemoveMember(ctx context.Context, request RemoveMemberRequestObject) (RemoveMemberResponseObject, error)
	// Change a member's role.
	// (PATCH /orgs/{orgId}/members/{userId})
	ChangeMemberRole(ctx context.Context, request ChangeMemberRoleRequestObject) (ChangeMemberRoleResponseObject, error)
	// The live per-region check state for the org's monitors (RFC-004 §9): each monitor maps to its regions' current state (scheduled/running/done/failed) with the last outcome. The frontend polls this to render a chip per region. Pass monitor_id to fetch one monitor. Monitors with no live state are omitted.
	// (GET /orgs/{orgId}/monitor-region-states)
	GetMonitorRegionStates(ctx context.Context, request GetMonitorRegionStatesRequestObject) (GetMonitorRegionStatesResponseObject, error)

	// (GET /orgs/{orgId}/monitors)
	ListMonitors(ctx context.Context, request ListMonitorsRequestObject) (ListMonitorsResponseObject, error)

	// (POST /orgs/{orgId}/monitors)
	CreateMonitor(ctx context.Context, request CreateMonitorRequestObject) (CreateMonitorResponseObject, error)

	// (DELETE /orgs/{orgId}/monitors/{id})
	DeleteMonitor(ctx context.Context, request DeleteMonitorRequestObject) (DeleteMonitorResponseObject, error)

	// (GET /orgs/{orgId}/monitors/{id})
	GetMonitor(ctx context.Context, request GetMonitorRequestObject) (GetMonitorResponseObject, error)

	// (PUT /orgs/{orgId}/monitors/{id})
	UpdateMonitor(ctx context.Context, request UpdateMonitorRequestObject) (UpdateMonitorResponseObject, error)
	// Trigger a check now. It enqueues one probe per region (like a scheduled check) and returns 202 immediately; the per-region progress shows up in the monitor's live region states (poll getMonitorRegionStates). 409 if a check is already running, the monitor is disabled, or you are within the per-monitor cooldown; 429 if you are over the sustained manual-check budget.
	// (POST /orgs/{orgId}/monitors/{id}/check)
	CheckNow(ctx context.Context, request CheckNowRequestObject) (CheckNowResponseObject, error)

	// (GET /orgs/{orgId}/monitors/{id}/incidents)
	ListMonitorIncidents(ctx context.Context, request ListMonitorIncidentsRequestObject) (ListMonitorIncidentsResponseObject, error)
	// The captured response from the monitor's most recent failed check (PRD-002 3.8).
	// (GET /orgs/{orgId}/monitors/{id}/last-failure)
	GetLastFailure(ctx context.Context, request GetLastFailureRequestObject) (GetLastFailureResponseObject, error)

	// (GET /orgs/{orgId}/monitors/{id}/results)
	ListResults(ctx context.Context, request ListResultsRequestObject) (ListResultsResponseObject, error)

	// (GET /orgs/{orgId}/status-pages)
	ListStatusPages(ctx context.Context, request ListStatusPagesRequestObject) (ListStatusPagesResponseObject, error)
	// Create a status page (member+; PRD-004 10).
	// (POST /orgs/{orgId}/status-pages)
	CreateStatusPage(ctx context.Context, request CreateStatusPageRequestObject) (CreateStatusPageResponseObject, error)

	// (DELETE /orgs/{orgId}/status-pages/{id})
	DeleteStatusPage(ctx context.Context, request DeleteStatusPageRequestObject) (DeleteStatusPageResponseObject, error)

	// (GET /orgs/{orgId}/status-pages/{id})
	GetStatusPage(ctx context.Context, request GetStatusPageRequestObject) (GetStatusPageResponseObject, error)
	// Update a status page and its displayed monitors (member+).
	// (PUT /orgs/{orgId}/status-pages/{id})
	UpdateStatusPage(ctx context.Context, request UpdateStatusPageRequestObject) (UpdateStatusPageResponseObject, error)
	// Publish or unpublish a status page (member+; PRD-004 6). Publishing makes the public URL resolve; unpublishing returns it to draft and stops resolving.
	// (PUT /orgs/{orgId}/status-pages/{id}/publish)
	PublishStatusPage(ctx context.Context, request PublishStatusPageRequestObject) (PublishStatusPageResponseObject, error)
	// Hand ownership to another member (owner only). The new owner must already be a member. The acting owner may step down to admin or stay an owner.
	// (POST /orgs/{orgId}/transfer-ownership)
	TransferOwnership(ctx context.Context, request TransferOwnershipRequestObject) (TransferOwnershipResponseObject, error)
	// The org's outbound webhooks (the signing secret is never returned).
	// (GET /orgs/{orgId}/webhooks)
	ListWebhooks(ctx context.Context, request ListWebhooksRequestObject) (ListWebhooksResponseObject, error)
	// Register an outbound webhook. The signing secret is returned exactly once in this response and never again. url must be https.
	// (POST /orgs/{orgId}/webhooks)
	CreateWebhook(ctx context.Context, request CreateWebhookRequestObject) (CreateWebhookResponseObject, error)
	// Delete an outbound webhook. Pulse Pager stops delivering to it immediately.
	// (DELETE /orgs/{orgId}/webhooks/{id})
	DeleteWebhook(ctx context.Context, request DeleteWebhookRequestObject) (DeleteWebhookResponseObject, error)
	// One outbound webhook (the signing secret is redacted).
	// (GET /orgs/{orgId}/webhooks/{id})
	GetWebhook(ctx context.Context, request GetWebhookRequestObject) (GetWebhookResponseObject, error)
	// Update an outbound webhook's url, enabled flag, and subscribed events.
	// (PUT /orgs/{orgId}/webhooks/{id})
	UpdateWebhook(ctx context.Context, request UpdateWebhookRequestObject) (UpdateWebhookResponseObject, error)
	// Rotate the signing secret. The new secret is returned exactly once in this response; the old one stops verifying immediately.
	// (POST /orgs/{orgId}/webhooks/{id}/rotate-secret)
	RotateWebhookSecret(ctx context.Context, request RotateWebhookSecretRequestObject) (RotateWebhookSecretResponseObject, error)
	// The public plan catalog (tiers and their limits).
	// (GET /plans)
	ListPlans(ctx context.Context, request ListPlansRequestObject) (ListPlansResponseObject, error)
	// The public, unauthenticated data endpoint a published status page renders from (PRD-004 3.6, 8). No auth, no org context. Returns only the public-safe projection; a draft or unknown slug is a 404 (PRD-004 6). Read-mostly and cacheable so the page stays up during the customer's own incident (PRD-004 8).
	// (GET /public/status-pages/{slug})
	GetPublicStatusPage(ctx context.Context, request GetPublicStatusPageRequestObject) (GetPublicStatusPageResponseObject, error)
}

type StrictHandlerFunc func(ctx context.Context, w http.ResponseWriter, r *http.Request, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// LogoutAll operation middleware
func (sh *strictHandler) LogoutAll(w http.ResponseWriter, r *http.Request) {
	var request LogoutAllRequestObject

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.LogoutAll(ctx, request.(LogoutAllRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "LogoutAll")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(LogoutAllResponseObject); ok {
		if err := validResponse.VisitLogoutAllResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

